const eventos = $('Buscar Eventos').all();
const dataCheckinReq = new Date($('When Executed by Another Workflow').item.json.data_inicio);
const dataCheckoutReq = new Date($('When Executed by Another Workflow').item.json.data_fim);

// Regra de Negócio: Check-out às 10h, Check-in às 14h.
// Se um evento existente terminar EXATAMENTE no mesmo dia que o check-in solicitado, NÃO é conflito.
// Se um evento existente começar EXATAMENTE no mesmo dia que o check-out solicitado, NÃO é conflito.

let temConflito = false;

for (const item of eventos) {
  const evt = item.json;
  if(!evt.start || !evt.end) continue;

  const evtStart = new Date(evt.start.dateTime || evt.start.date);
  const evtEnd = new Date(evt.end.dateTime || evt.end.date);

  // Zera horas para verificação apenas de sobreposição de diárias
  evtStart.setHours(0,0,0,0);
  evtEnd.setHours(0,0,0,0);
  dataCheckinReq.setHours(0,0,0,0);
  dataCheckoutReq.setHours(0,0,0,0);

  // Condição de Conflito Real
  if (dataCheckinReq < evtEnd && dataCheckoutReq > evtStart) {
    temConflito = true;
    break;
  }
}

// Prepara a devolução pro LLM
let status = temConflito ? 'ocupado' : 'livre';
let mensagem = temConflito ? 'Infelizmente a suíte está ocupada nesse período.' : 'A suíte está disponível! Deseja seguir com a pré-reserva?';

return [{ json: { status: status, mensagem: mensagem } }];
